type JobKey = "warrior" | "thief" | "priest" | "mage" | "knight" | "sage";
type Phase = "explore" | "battle" | "shop" | "bossChoice" | "relicChoice" | "recoveryChoice" | "ending";
type Point = { x: number; y: number };
type Tile = "#" | "." | ">" | "$" | "S";
type GearKind = "weapon" | "armor" | "accessory";
type EnemyIntent = "attack" | "heavy" | "guard" | "charge" | "status";
type StatusKind = "poison" | "bleed" | "curse" | "blind" | "paralysis";
type Status = { kind: StatusKind; turns: number };
type BattleFx = "" | "slash" | "magic" | "heal" | "blast" | "vanish";
type Gear = { id: string; name: string; kind: GearKind; tier: number; price: number; atk?: number; def?: number; hp?: number; mp?: number };
type OwnedGear = Gear & { uid: number };
type DungeonEnemy = { id: number; x: number; y: number; kind: number; boss: boolean; graveEater?: boolean };
type BattleEnemy = DungeonEnemy & { name: string; catalogId: string; hp: number; maxHp: number; atk: number; def: number; gold: number; exp: number; intent: EnemyIntent; turn: number };
type PendingEnemyTurn = { battle: BattleEnemy; message: string; skip: boolean };
type Run = {
  name: string; job: JobKey; phase: Phase; floor: number; level: number; exp: number; hp: number; mp: number;
  gold: number; totalGold: number; kills: number; bosses: number; seed: number; nextUid: number; map: Tile[][]; seen: boolean[][];
  player: Point; enemies: DungeonEnemy[]; opened: number[]; inventory: OwnedGear[]; equipment: Record<GearKind, OwnedGear | null>;
  potions: number; bombs: number; combo: number; relics: string[]; testMode: boolean; quest: string; recovery: OwnedGear[]; shopPotionAvailable: boolean; battle: BattleEnemy | null; pendingEnemyTurn: PendingEnemyTurn | null; guard: number; statuses: Status[]; message: string;
};
type Grave = { floor: number; items: OwnedGear[] };
type Meta = { version: 2; bestFloor: number; bestScore: number; totalKills: number; cleared: boolean; unlocked: JobKey[]; jobBest: Partial<Record<JobKey, number>>; mastery: Partial<Record<JobKey, number>>; titles: string[]; grave: Grave | null; bestiary: Record<string,number> };
type Result = { reason: "dead" | "return" | "abandon" | "clear"; floor: number; score: number; kills: number; bosses: number; unlocked: JobKey[]; name: string; job: JobKey; testMode: boolean };

