const normalizeMeta=(value:unknown):Meta|null=>{if(!value||typeof value!=="object")return null;const saved=value as Partial<Meta>;return{...defaultMeta,...saved,version:2,unlocked:Array.isArray(saved.unlocked)?saved.unlocked:defaultMeta.unlocked,jobBest:saved.jobBest??{},mastery:saved.mastery??{},titles:Array.isArray(saved.titles)?saved.titles:[],grave:saved.grave??null,bestiary:saved.bestiary??{}};};
const normalizeRun=(value:unknown):Run|null=>{if(!value||typeof value!=="object")return null;const saved=value as Partial<Run>;if(typeof saved.name!=="string"||!Object.keys(JOBS).includes(saved.job??"")||!(["explore","battle","shop","bossChoice","relicChoice","recoveryChoice","ending"] as string[]).includes(saved.phase??"")||!Number.isInteger(saved.floor)||Number(saved.floor)<1||Number(saved.floor)>100||!Array.isArray(saved.map)||saved.map.length!==H||!saved.map.every(row=>Array.isArray(row)&&row.length===W)||!saved.player||!Number.isInteger(saved.player.x)||!Number.isInteger(saved.player.y)||!saved.equipment)return null;return{...(saved as Run),bombs:saved.bombs??0,combo:saved.combo??0,relics:saved.relics??[],testMode:saved.testMode??false,quest:saved.quest??QUESTS[0],recovery:saved.recovery??[],shopPotionAvailable:saved.shopPotionAvailable??true,statuses:saved.statuses??[],pendingEnemyTurn:saved.pendingEnemyTurn??null,battle:saved.battle?{...saved.battle,intent:saved.battle.intent??"attack",turn:saved.battle.turn??0}:null};};

